<?php
namespace Database\Seeders;use App\Models\Content;use App\Models\User;use Illuminate\Database\Seeder;use Illuminate\Support\Facades\Hash;use Illuminate\Support\Str;
class DatabaseSeeder extends Seeder{public function run():void{$password=env('ADMIN_PASSWORD');if(!$password&&app()->isProduction())throw new \RuntimeException('Set ADMIN_PASSWORD before production seeding.');User::updateOrCreate(['email'=>env('ADMIN_EMAIL','admin@sysnettechs.co.ke')],['name'=>'Sysnettech Administrator','password'=>Hash::make($password?:'LocalAdmin!2026'),'role'=>'admin']);$services=['POS Systems'=>'Smart sales, inventory and M-Pesa workflows.','CCTV & Surveillance'=>'Intelligent security and remote visibility.','Web Development'=>'Fast websites and custom business platforms.','Biometric Systems'=>'Accurate attendance and access control.','Computer Networking'=>'Secure, reliable business connectivity.'];foreach($services as $title=>$excerpt)Content::updateOrCreate(['type'=>'services','slug'=>Str::slug($title)],['title'=>$title,'excerpt'=>$excerpt,'status'=>'published','published_at'=>now()]);foreach(['Multi-Branch Retail POS','Smart Factory Surveillance','Hospital Operations Portal'] as $title)Content::updateOrCreate(['type'=>'projects','slug'=>Str::slug($title)],['title'=>$title,'excerpt'=>'A scalable implementation delivered for a Kenyan organisation.','status'=>'published','published_at'=>now()]);}}
